export const guidelinesContent: Record<string, string> = {
  "component-structure": "# Component Structure\n\nComponents need correct sizing, property bindings, and token usage to work well as instances.\n\n## Width Constraints\n\nComponents with text content need a width — otherwise text never wraps.\n\n- Set `width` and `layoutSizingHorizontal:\"FIXED\"` on cards, panels, list items\n- HUG on both axes is only correct for buttons, badges, icons — intrinsically-sized elements\n\n## Property Bindings\n\nEvery text node inside a component should be bound to a TEXT property so instances can edit the content.\n\n- On creation: `children:[{type:\"text\", text:\"Title\", componentPropertyName:\"Title\"}]` auto-creates and binds\n- On creation: `children:[{type:\"text\", text:\"Title\", componentPropertyName:\"Title\"}]` auto-creates and binds\n- After creation: `frames(method:\"update\", items:[{id:\"<textNodeId>\", componentPropertyName:\"<propName>\"}])`\n- For existing nodes with many text children: `components(method:\"create\", type:\"from_node\", exposeText:true)`\n\nOrphaned properties (defined but not bound to any node) should be deleted:\n```\ncomponents(method:\"update\", items:[{id, propertyName:\"<key>\", action:\"delete\"}])\n```\n\n## Variant Sets\n\nGroup related components as variants — don't leave them as separate components.\n\n- Name variants with the property format: `Style=Primary`, `Style=Secondary`\n- Combine: `components(method:\"create\", type:\"variant_set\", items:[{componentIds:[...], name:\"Button\"}])`\n- Instances pick variants via `variantProperties:{\"Style\":\"Primary\"}`\n\n### Adding Variants to an Existing Set\n\nClone an existing variant into the same set with a new name. The `name` param is required — without it, the duplicate name corrupts the set.\n\n**Add a new value to an existing dimension** (e.g. State=Hover):\n```\ncomponents(method:\"clone\", id:\"<variant_id>\", name:\"Style=Primary, State=Hover\", parentId:\"<set_id>\")\n```\nClone one variant per combination. For a Style×State set, adding State=Hover requires two clones (one per Style). Use batch `items` for efficiency:\n```\ncomponents(method:\"clone\", items:[\n  {id:\"<Primary/Default>\", name:\"Style=Primary, State=Hover\", parentId:\"<set_id>\"},\n  {id:\"<Secondary/Default>\", name:\"Style=Secondary, State=Hover\", parentId:\"<set_id>\"}\n])\n```\nThen patch the new variants: `frames(method:\"update\", items:[{id:\"<new>\", fillVariableName:\"color/hover\"}])`\n\n**Add a new dimension** (e.g. Size=sm to a Style×State set):\n1. Batch rename existing variants to include the new dimension: `frames(method:\"update\", items:[{id:\"<each>\", name:\"..., Size=md\"}])`\n2. Batch clone all variants with the new value: `components(method:\"clone\", items:[{id:\"<each>\", name:\"..., Size=sm\", parentId:\"<set_id>\"}])`\n3. Batch patch the new variants: `frames(method:\"update\", items:[{id:\"<each>\", padding:8, minHeight:32}])`\n\nProperty bindings (TEXT, INSTANCE_SWAP) are preserved on cloned variants.\n\n## Slots\n\nSlots are placeholder containers inside components that instance users can fill with custom content.\n\n- Create at component root: `frames(method:\"create\", type:\"slot\", items:[{parentId:\"<comp_id>\", name:\"Content\"}])`\n- Create nested inside a frame within a component: `frames(method:\"create\", type:\"slot\", items:[{parentId:\"<frame_id>\", name:\"Content\"}])`\n- In instances, add content by using the slot's ID as `parentId` on any create/reparent call\n- Empty slots are normal — they don't trigger lint warnings\n\n## Checking\n\nRun `components(method:\"audit\", id)` — checks both lint rules and property bindings in one call.",
  "library-components": "# Working with Library Components\n\nLibrary components are read-only — they come from external team libraries and cannot be edited in the current file.\n\n## Reading\n\nWhen reading nodes, library instances appear as stubs with their overridable properties:\n```\n{name: \"Header\", type: \"INSTANCE\", componentProperties: {\"Platform\": \"Desktop\"}}\n```\n\nLibrary internals are hidden: no `componentId`, no variable names, no style names. You see resolved values (hex colors, numbers) instead.\n\n## Using\n\nPlace library instances via `instances(method:\"create\", items:[{componentId:\"<id>\"}])` when you have a local component ID. For library components, instances are already placed by the designer — interact via `instances(method:\"update\")` to set properties.\n\n## Customizing\n\nTo edit a library component, clone it into the local file first:\n\n```\ncomponents(method:\"clone\", id:\"<instanceId>\")\n```\n\nThis resolves the instance to its source component (or full component set) and creates a local copy with a new ID. Edit the local copy freely — it is independent of the library.\n\nDo not attempt to `components(method:\"get\")` or `components(method:\"update\")` a library component directly — these will error.\n\n## Overriding Instance Properties\n\nUse `instances(method:\"update\")` to change overridable properties on library instances:\n```\ninstances(method:\"update\", items:[{id:\"<instanceId>\", properties:{\"Label\":\"New Text\", \"State\":\"Hover\"}}])\n```\n\nProperty names are clean (no hash suffixes needed for update — the system resolves partial keys).",
  "responsive-designs": "# Responsive Sizing\n\n## Workflow: Top-Down Sizing\n\nBuild layouts from the outside in:\n\n1. **Set the container first.** Every container needs an explicit width — either `width` + `layoutSizingHorizontal:\"FIXED\"` for shells and bounded panels, or `layoutSizingHorizontal:\"FILL\"` inside an auto-layout parent. Set `layoutMode` (VERTICAL or HORIZONTAL) and spacing/padding.\n2. **Children fill the container.** Use `layoutSizingHorizontal:\"FILL\"` on children so they stretch to the available space. Use `layoutSizingVertical:\"HUG\"` so height follows content.\n3. **Only leaves use HUG on both axes.** Buttons, badges, icons — elements with short, predictable content that should shrink-wrap.\n\nThis ensures every level of the tree has a clear width constraint. Text wraps, FILL children stretch, and the layout adapts when the container resizes.\n\nAlways set BOTH axes explicitly on every node. Omitting sizing leads to unintended defaults.\n\n## FIXED / FILL / HUG\n\n- **FIXED** — explicit bounded widths: page shell, sidebar, modal max-width, specimen frames\n- **FILL** — children that adapt to parent: cards, rows, panels, nav stacks, text that should wrap. Use `minWidth`/`maxWidth` for responsive constraints.\n- **HUG** — content-sized leaves only: icons, badges, pills, button labels\n\n## Anti-patterns: HUG/HUG\n\nHUG on both axes is the most common cause of broken layouts. It means \"shrink to fit my content on both axes\" — the container has no opinion about its own size and collapses to whatever its children measure.\n\n**Why HUG/HUG breaks designs:**\n\n1. **Text never wraps.** A HUG-width container grows to fit the longest text line. Body text becomes a single very long line instead of wrapping at a readable width. The design looks correct with short placeholder text but breaks with real content.\n\n2. **Layouts don't adapt.** HUG/HUG containers ignore their parent's width. A card inside a responsive column won't stretch to fill available space — it stays at its content width, leaving gaps or overflowing.\n\n3. **FILL children become under-constrained.** A child with `layoutSizingHorizontal:\"FILL\"` inside a HUG-width parent has no space to fill — the parent defers its width to its children, but the FILL child defers its width to the parent. The result is under-constrained sizing that produces unpredictable or collapsed layouts.\n\n4. **Cascading failures.** One HUG/HUG container at the top of a tree forces every child to resolve its own width. The entire layout becomes rigid and content-dependent instead of responsive.\n\n**HUG/HUG is only correct for:**\n- Buttons, pills, badges, chips — intrinsically-sized leaf elements with short, predictable content\n- Icon containers with fixed-size children\n- Inline tags and status indicators\n\n**For everything else, set at least one axis to FIXED or FILL:**\n- Cards, panels, list rows → `layoutSizingHorizontal:\"FILL\"`, vertical `HUG`. Add `minWidth`/`maxWidth` for responsive bounds.\n- Shells, sidebars, modals → `width` + `layoutSizingHorizontal:\"FIXED\"`, vertical `FILL` or `HUG`\n- Full-width sections → `layoutSizingHorizontal:\"FILL\"`, `layoutSizingVertical:\"HUG\"`\n\n## Wrapping Layouts (layoutWrap)\n\n`layoutWrap: WRAP` enables children to flow into new rows when they exceed the container width — like CSS `flex-wrap`. This only works with **HORIZONTAL** auto-layout. Figma does not support wrap on VERTICAL layouts.\n\n**When to use wrap:**\n- Card grids with a fixed number of columns at a known width\n- Tag/chip collections where items flow into multiple rows\n- Any layout where items should reflow based on available width\n\n**Horizontal wrap pattern:**\n```\nframes.create(type: \"auto_layout\", layoutMode: \"HORIZONTAL\", layoutWrap: \"WRAP\",\n  itemSpacing: \"space/16\", counterAxisSpacing: \"space/16\")\n```\nChildren use FIXED width to control column count. `counterAxisSpacing` sets the gap between wrapped rows.\n\n**Vertical grid alternative:**\nSince VERTICAL layouts cannot wrap, build column-based grids by nesting VERTICAL columns inside a HORIZONTAL parent:\n```\nouter (HORIZONTAL, itemSpacing: 20, FILL width)\n  col-1 (VERTICAL, FILL width, HUG height, itemSpacing: 20)\n  col-2 (VERTICAL, FILL width, HUG height, itemSpacing: 20)\n  col-3 (VERTICAL, FILL width, HUG height, itemSpacing: 20)\n```\nEach column gets equal width via FILL. Reparent items into columns for column-first ordering. This handles variable card heights per column independently.\n\n## Component Sizing\n\nComponent roots use `FILL` when placed in a parent — they adapt to context, not a fixed specimen width. Use `FIXED` only for the specimen (the component definition itself when it needs a specific preview width).\n\nExample sidebar item:\n- Instance: `FILL` in parent nav stack\n- Icon child: fixed 18x18\n- Label child: `FILL`\n- Badge child: `HUG`\n\n## Text Sizing\n\n- Body text inside containers: prefer `FILL` width, `HUG` height (auto-wraps)\n- Single-line labels: prefer `FILL` horizontal (truncates if needed)\n- Standalone headings: `HUG` is fine\n\nInside auto-layout parents, target `layoutSizingHorizontal:\"FILL\"` + `layoutSizingVertical:\"HUG\"` + `textAutoResize:\"HEIGHT\"` for text that should wrap. These are not auto-applied — set them explicitly on text.create or text.update.\n\n## Checklist\n\nBefore finalizing a layout, verify:\n1. No container with text has HUG on the horizontal axis (unless it's a button/badge)\n2. Children use FILL on the axis that should absorb available space — not blindly on both axes. Compact controls in horizontal rows often stay HUG vertically.\n3. Top-level containers have an explicit width (FIXED) or stretch to their parent (FILL)\n4. Run `lint(method:\"check\", nodeId:\"<rootId>\", rules:[\"composition\"])` to catch overflow-parent, unbounded-hug, and fixed-in-autolayout issues",
  "token-discipline": "# Token Discipline\n\nEvery color, spacing value, and text style should come from a design token — not hardcoded values.\n\n## Colors\n\nBind fills and strokes to color variables instead of hex values.\n\n- Fill: `fillVariableName:\"bg/primary\"` or `fillStyleName:\"Surface/Primary\"`\n- Stroke: `strokeVariableName:\"border/default\"`\n- Text color: `fontColorVariableName:\"text/primary\"`\n\nIf no matching variable exists, create one first:\n```\nvariables(method:\"create\", collectionId:\"Colors\", items:[{name:\"bg/accent\", type:\"COLOR\", valuesByMode:{\"Light\":\"#E8F0FE\",\"Dark\":\"#1A3A5C\"}, scopes:[\"ALL_FILLS\"]}])\n```\n\n## Spacing and Radius\n\nPass a variable name string instead of a number for cornerRadius, padding, itemSpacing, strokeWeight, opacity.\n\n- `cornerRadius:\"radius/8\"` not `cornerRadius:8`\n- `paddingTop:\"space/16\"` not `paddingTop:16`\n- `itemSpacing:\"space/8\"` not `itemSpacing:8`\n\nCreate FLOAT variables with appropriate scopes:\n```\nvariables(method:\"create\", collectionId:\"Metrics\", items:[{name:\"space/12\", type:\"FLOAT\", value:12, scopes:[\"GAP\",\"WIDTH_HEIGHT\"]}])\n```\n\n## Text Styles\n\nApply text styles by name — don't set fontSize/fontFamily/fontWeight manually.\n\n- `textStyleName:\"Body/M\"` on text.create or frames.update\n- Create styles with `styles(method:\"create\", type:\"text\", items:[{name:\"Body/M\", fontFamily:\"Inter\", fontSize:14, lineHeight:{value:20, unit:\"PIXELS\"}}])`\n\n## Common Scopes\n\nCOLOR variables:\n- `ALL_FILLS` — background fills\n- `TEXT_FILL` — text color\n- `STROKE_COLOR` — borders and outlines\n\nFLOAT variables:\n- `GAP`, `WIDTH_HEIGHT` — spacing and padding\n- `CORNER_RADIUS` — border radius\n- `STROKE_FLOAT` — stroke weight\n- `OPACITY` — transparency\n\n## Checking\n\nLint rules `hardcoded-color`, `hardcoded-token`, `no-text-style` catch unbound values. Run `audit` on any node to check.",
  "vibma-workflow": "# Vibma Workflow\n\nWork with the tool in a predictable sequence: read before writing, create parents before children, verify after mutations.\n\n## Build Order\n\n1. `connection.create` → `connection.get` to verify\n2. Inspect existing structure: `document.get`, `variables.list`, `styles.list`, `components.list`\n3. Create design tokens: variable collections → variables → text styles → effect styles\n4. Create components from tokens\n5. Assemble screens from component instances\n6. Verify with `lint.check` and `frames.export`\n\n## Parent-First Rule\n\nCreate parent containers before children. Dependent creates must be sequential — never parallelize when the child needs the parent ID.\n\n## Component Creation\n\nBuild components early — they are the building blocks for screens. A component IS a frame: create it directly with layout properties, then add children.\n\n- Use `components.create(type: \"component\")` with properties for TEXT, BOOLEAN, INSTANCE_SWAP\n- TEXT properties auto-bind to child text nodes with matching names\n- Group related components into variant sets with `components.create(type: \"variant_set\")` for state dimensions (Style, Size, State)\n- Use flat components (not variant sets) for INSTANCE_SWAP slots like icons or avatars\n- Assemble screens from `instances.create`, not by cloning frames\n\n## Placement Rule\n\nAlways pass `x` and `y` for top-level nodes and clones. Do not stack everything at `0,0`.\n\n## Instance Rule\n\nCall `components.get` or `instances.get` to discover property keys (including `#suffix`) before setting overrides. Do not guess property names.\n\n## Verify After Mutations\n\n`\"ok\"` means the write succeeded, not that the result is correct. Read back the node after clone, swap, mode pinning, or large batch updates."
};

/** Resolve a guidelines query. */
export function resolveGuideline(topic?: string): string {
  if (!topic) {
    const dir = ["# Design Guidelines", ""];
    for (const g of guidelinesList) {
      dir.push("  " + g.name.padEnd(30) + g.title);
    }
    dir.push("");
    dir.push('Use guidelines(topic: "<name>") for full guideline text.');
    return dir.join("\n");
  }
  const content = guidelinesContent[topic];
  if (content) return content;
  const names = guidelinesList.map(g => g.name);
  return "Unknown guideline: " + topic + ". Available: " + names.join(", ");
}
